export function getMassachusettsWeightLossClinicsByCity(citySlug: string): WeightLossClinic[] {
  return massachusettsWeightLossClinics.filter(c => c.citySlug === citySlug);
}

export function getMassachusettsWeightLossCitiesWithClinics(): { city: string; citySlug: string; count: number }[] {
  const map = new Map<string, { city: string; citySlug: string; count: number }>();
  for (const c of massachusettsWeightLossClinics) {
    const e = map.get(c.citySlug) || { city: c.city, citySlug: c.citySlug, count: 0 };
    e.count++; map.set(c.citySlug, e);
  }
  return Array.from(map.values());
}
